Install:
npx -y @smithery/cli@latest install @SaseQ/discord-mcp --client claude && claude mcp list

Config:
{
  "discord-mcp": {
    "env": {
      "DISCORD_TOKEN": "${DISCORD_TOKEN}",
      "DISCORD_GUILD_ID": "${DISCORD_GUILD_ID}"
    },
    "args": [
      "-jar",
      "/absolute/path/to/discord-mcp-0.0.1-SNAPSHOT.jar"
    ],
    "command": "java"
  }
}

Usage:
{
  "discord-mcp": {
    "env": {
      "DISCORD_TOKEN": "${DISCORD_TOKEN}",
      "DISCORD_GUILD_ID": "${DISCORD_GUILD_ID}"
    },
    "args": [
      "-jar",
      "/absolute/path/to/discord-mcp-0.0.1-SNAPSHOT.jar"
    ],
    "command": "java"
  }
}
